unsigned __int64 sub_4008F6()&#123;  char buf; // [rsp+0h] [rbp-40h]  int v2; // [rsp+30h] [rbp-10h]  unsigned __int64 v3; // [rsp+38h] [rbp-8h]  v3 = __readfsqword(0x28u);  puts(&quot;To seek the truth of the world.&quot;);  read(0, &amp;buf, 0x80uLL);  if ( v2 != 9011 )    exit(0);  return __readfsqword(0x28u) ^ v3;&#125;
要求 v2 &#x3D;&#x3D; 9011，通过上面的 read 栈溢出控制 v2，但是不能直接控制返回地址，因为程序开启了 canary。第二关代码：
